<?php
declare(strict_types=1);namespace Vigilancia\Services;use Vigilancia\Exceptions\HttpException;
final class OfflineEvidenceService{public function __construct(private string$root){}public function save(?string$data):?string{if(!$data)return null;if(!preg_match('#^data:(image/(?:jpeg|png|webp)|video/(?:mp4|webm));base64,(.+)$#s',$data,$m))throw new HttpException('La evidencia offline no tiene un formato permitido.',422);$bin=base64_decode($m[2],true);if($bin===false||strlen($bin)>20*1024*1024)throw new HttpException('La evidencia offline supera 20 MB o estÃ¡ daÃ±ada.',422);$mime=(new \finfo(FILEINFO_MIME_TYPE))->buffer($bin);$ext=['image/jpeg'=>'jpg','image/png'=>'png','image/webp'=>'webp','video/mp4'=>'mp4','video/webm'=>'webm'];if(!isset($ext[$mime]))throw new HttpException('El MIME real de la evidencia no estÃ¡ permitido.',422);$dir=$this->root.'/storage/offline/'.gmdate('Y/m');if(!is_dir($dir)&&!mkdir($dir,0775,true)&&!is_dir($dir))throw new \RuntimeException('No se pudo preparar la evidencia offline.');$rel='storage/offline/'.gmdate('Y/m').'/'.bin2hex(random_bytes(20)).'.'.$ext[$mime];if(file_put_contents($this->root.'/'.$rel,$bin,LOCK_EX)===false)throw new \RuntimeException('No se pudo guardar la evidencia offline.');return$rel;}}
